:root {
  --color-bg:       #111111;
  --color-surface:  #1e1e1e;
  --color-accent:   #f5a623;
  --color-on-accent:#111111;
  --color-error:    #e53935;
  --color-on-error: #ffffff;
  --color-text:     #f0f0f0;
  --color-muted:    #888888;
  --color-border:   #333333;
  --font-main:      'Barlow Condensed', sans-serif;
  --radius:         12px;
  --map-height:     180px;
}

/* ═══════════════════════════════════════════
   RESET
═══════════════════════════════════════════ */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

/* ═══════════════════════════════════════════
   BASE
═══════════════════════════════════════════ */
body {
  font-family: var(--font-main);
  background: var(--color-bg);
  color: var(--color-text);
  min-height: 100vh;
}

/* ═══════════════════════════════════════════
   APP SHELL
═══════════════════════════════════════════ */
#app {
  max-width: 480px;
  margin: 0 auto;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

/* ═══════════════════════════════════════════
   HEADER
═══════════════════════════════════════════ */
#header {
  position: sticky;
  top: 0;
  z-index: 10;
  background: var(--color-bg);
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 12px 16px;
  border-bottom: 1px solid var(--color-border);
}

#logo-block {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

#logo {
  font-size: 1.4rem;
  font-weight: 700;
  letter-spacing: 0.04em;
  color: var(--color-accent);
  text-transform: uppercase;
}

#logo-sub {
  font-size: 0.7rem;
  color: var(--color-muted);
  text-transform: uppercase;
  letter-spacing: 0.06em;
}

#usage-counter {
  font-size: 0.75rem;
  color: var(--color-muted);
}

/* ═══════════════════════════════════════════
   MAIN
═══════════════════════════════════════════ */
#main {
  flex: 1;
  display: flex;
  flex-direction: column;
  padding: 24px 16px;
  gap: 16px;
}

/* ═══════════════════════════════════════════
   STATE VISIBILITY — default: all panels hidden
═══════════════════════════════════════════ */
#voice-mode,
#status-bar,
#confirm-panel,
#result-panel,
#error-panel {
  display: none;
}

/* idle — voice-mode + status-bar */
body[data-state="idle"] #voice-mode,
body[data-state="idle"] #status-bar {
  display: flex;
}

/* recording — voice-mode + status-bar */
body[data-state="recording"] #voice-mode,
body[data-state="recording"] #status-bar {
  display: flex;
}

/* transcribing — voice-mode + status-bar */
body[data-state="transcribing"] #voice-mode,
body[data-state="transcribing"] #status-bar {
  display: flex;
}

/* confirming */
body[data-state="confirming"] #confirm-panel {
  display: flex;
}

/* processing — confirm-panel visible, loading block shown */
body[data-state="processing"] #confirm-panel {
  display: flex;
}
body[data-state="processing"] #confirm-loading {
  display: flex;
}

/* result */
body[data-state="result"] #result-panel {
  display: flex;
}

/* error */
body[data-state="error"] #error-panel {
  display: flex;
}

/* ═══════════════════════════════════════════
   VOICE MODE
═══════════════════════════════════════════ */
#voice-mode {
  flex-direction: column;
  align-items: center;
  gap: 20px;
